import React from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { DashboardIcon, ClassifierIcon, ChatIcon, AboutIcon } from './Icons';

const navItems = [
  { label: 'Dashboard', path: '/dashboard', icon: DashboardIcon },
  { label: 'Classifier', path: '/classifier', icon: ClassifierIcon },
  { label: 'Chat', path: '/chat', icon: ChatIcon },
  { label: 'About', path: '/about', icon: AboutIcon },
];

export default function Sidebar({ open, onClose, session, onLogout, predictionHistory, chatHistory, restorePrediction, restoreChat, collapsed, onToggleCollapse }) {
  const navigate = useNavigate();

  const handlePredictionClick = (item) => {
    restorePrediction(item);
    navigate('/classifier');
    onClose();
  };

  const handleChatClick = (item) => {
    restoreChat(item);
    navigate('/chat');
    onClose();
  };

  return (
    <aside className={`sidebar ${open ? 'sidebar-open' : ''} ${collapsed ? 'collapsed' : ''}`}>
      <div className="sidebar-inner">
        <div className="sidebar-brand">
          <div className="brand-avatar">B</div>
          {!collapsed && (
            <div>
              <h1>Bovine Classifier</h1>
              <p>Breed intelligence dashboard</p>
            </div>
          )}
        </div>

        <nav className="sidebar-nav">
          {navItems.map((item) => {
            const Icon = item.icon;
            return (
              <NavLink
                key={item.path}
                to={item.path}
                className={({ isActive }) => (isActive ? 'nav-link active' : 'nav-link')}
                onClick={onClose}
                title={collapsed ? item.label : undefined}
              >
                <Icon />
                {!collapsed && <span>{item.label}</span>}
              </NavLink>
            );
          })}
        </nav>

        {!collapsed && (
          <div className="sidebar-section">
            <div className="sidebar-section-title">History</div>

            <div className="sidebar-history-group">
              <div className="sidebar-history-label">Predictions</div>
              {predictionHistory.length ? (
                predictionHistory.slice(0, 4).map((item) => (
                  <button
                    type="button"
                    key={item.id}
                    className="sidebar-history-item"
                    onClick={() => handlePredictionClick(item)}
                  >
                    <span>{item.breedName}</span>
                    <small>{new Date(item.createdAt).toLocaleDateString()}</small>
                  </button>
                ))
              ) : (
                <div className="sidebar-history-empty">No saved predictions yet</div>
              )}
            </div>

            <div className="sidebar-history-group">
              <div className="sidebar-history-label">Chat sessions</div>
              {chatHistory.length ? (
                chatHistory.slice(0, 4).map((item) => (
                  <button
                    type="button"
                    key={item.id}
                    className="sidebar-history-item"
                    onClick={() => handleChatClick(item)}
                  >
                    <span>{item.title}</span>
                    <small>{new Date(item.createdAt).toLocaleDateString()}</small>
                  </button>
                ))
              ) : (
                <div className="sidebar-history-empty">No chats yet</div>
              )}
            </div>
          </div>
        )}

        <div className="sidebar-footer">
          <div className="sidebar-user-avatar">
            {session?.username?.charAt(0).toUpperCase()}
          </div>
          {!collapsed && (
            <div>
              <div className="sidebar-user-name">{session?.username}</div>
              <div className="sidebar-user-email">{session?.email}</div>
            </div>
          )}
          <button type="button" className="sidebar-logout" onClick={onLogout}>
            {!collapsed ? 'Logout' : '×'}
          </button>
        </div>
        <button type="button" className="sidebar-collapse-toggle" onClick={onToggleCollapse}>
          {collapsed ? '→' : '←'}
        </button>
      </div>
      <motion.button
        className="sidebar-backdrop"
        initial={{ opacity: 0 }}
        animate={{ opacity: open ? 1 : 0 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
      />
    </aside>
  );
}
